import { FOCUSABLE_SELECTOR } from "../../utils/focusableSelector";
export const findNextFocusable = (element) => {
    if (!element) {
        return undefined;
    }
    const listItemEl = element.closest("li");
    let nextElement = listItemEl.nextElementSibling;
    while (nextElement) {
        if (nextElement.querySelector(FOCUSABLE_SELECTOR)) {
            return nextElement.querySelector(FOCUSABLE_SELECTOR);
        }
        nextElement = nextElement.nextElementSibling;
    }
    return listItemEl.parentNode.querySelector(FOCUSABLE_SELECTOR);
};
