import { useCallback, useState } from "react";
export const useFeedExpandable = (isMobile, feedExpandableOptions) => {
    const { isExpanded = false, visibleColumns = 5 } = feedExpandableOptions || {};
    const [isFeedExpanded, setIsFeedExpanded] = useState(isExpanded);
    const handleExpanded = useCallback(() => setIsFeedExpanded(prev => !prev), []);
    const isFeedVisible = !!(isMobile && feedExpandableOptions);
    return {
        isFeedExpanded,
        handleExpanded,
        isFeedVisible,
        visibleColumns
    };
};
